'use client';

import React, { useEffect, useState } from 'react';
import { useParams, useRouter } from 'next/navigation';
import axios from 'axios';
import {
  Card,
  CardHeader,
  CardTitle,
  CardContent,
} from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogFooter,
} from '@/components/ui/dialog';
import { Input } from '@/components/ui/input';
import {
  Select,
  SelectTrigger,
  SelectValue,
  SelectContent,
  SelectItem
} from '@/components/ui/select';
import {
  Mail,
  UserCheck,
  UserX,
  Edit2,
  Trash,
  Package,
  Calendar
} from 'lucide-react';

const API_BASE_URL = process.env.NEXT_PUBLIC_API_BASE_URL;

interface UserType {
  _id: string;
  name: string;
  email: string;
  role: 'admin' | 'customer';
}

interface OrderType {
  items: any;
  createdAt: string | number | Date;
  _id: string;
  date: string;
  total: number;
  status: 'Pending' | 'Shipped' | 'Delivered' | 'Cancelled';
}

export default function UserDetailPage() {
  const params = useParams();
  const router = useRouter();
  const userId = params?.id;

  const [user, setUser] = useState<UserType | null>(null);
  const [orders, setOrders] = useState<OrderType[]>([]);
  const [openEditDialog, setOpenEditDialog] = useState(false);
  const [editForm, setEditForm] = useState({
    name: '',
    email: ''
  });

  if (!userId || Array.isArray(userId)) {
    return <div className="p-6 text-red-600">Invalid user ID</div>;
  }

  useEffect(() => {
    const fetchData = async () => {
      try {
        const userRes = await axios.get(`${API_BASE_URL}/api/auth/users/${userId}`);
        setUser(userRes.data);
        setEditForm({
          name: userRes.data.name,
          email: userRes.data.email

        });

        const orderRes = await axios.get(
          `${API_BASE_URL}/api/orders/user/${userId}`
        );
        setOrders(orderRes.data);

      } catch (error: any) {
        console.error(error.response?.data || error.message);
        alert("Failed to fetch user data");
      }
    };

    fetchData();
  }, [userId]);

  const handleDeleteUser = async () => {
    if (!user) return;
    if (!confirm('Are you sure you want to delete this user?')) return;

    try {
      await axios.delete(`${API_BASE_URL}/api/users/${user._id}`);
      router.push('/admin/user');
    } catch (error: any) {
      console.error(error.response?.data || error.message);
      alert("Delete failed");
    }
  };

  const handleCancelOrder = async (orderId: string) => {
    if (!confirm('Are you sure you want to cancel this order?')) return;

    try {
      await axios.put(`${API_BASE_URL}/api/orders/${orderId}/cancel`);

      setOrders(prev =>
        prev.map(o =>
          o._id === orderId ? { ...o, status: 'Cancelled' } : o
        )
      );
    } catch (error: any) {
      console.error(error.response?.data || error.message);
      alert("Cancel failed");
    }
  };

  const handleSaveEdit = async () => {
    if (!editForm.name || !editForm.email) {
      return alert('Fill all fields');
    }

    try {
      const res = await axios.put(
        `${API_BASE_URL}/api/users/${user?._id}`,
        editForm
      );

      setUser(res.data);
      setOpenEditDialog(false);
    } catch (error: any) {
      console.error(error.response?.data || error.message);
      alert("Update failed");
    }
  };

  if (!user) return <div className="p-6 text-gray-600">User not found.</div>;

  const firstOrder = orders[0];
  const lastOrder = orders[orders.length - 1];

  return (
    <div className="p-6 max-w-5xl mx-auto space-y-6">
      <h1 className="text-2xl font-bold mb-4">User Details</h1>

      {/* User Info Card */}
      <Card className="bg-white shadow hover:shadow-lg transition">
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            {user.role === 'admin' ? <UserCheck size={20} /> : <UserX size={20} />} {user.name}
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-2">
          <p className="flex items-center gap-2"><Mail size={16} /> {user.email}</p>


          <div className="flex justify-end gap-2 mt-4">
            <Button onClick={() => setOpenEditDialog(true)}>
              <Edit2 size={14} /> Edit
            </Button>
            <Button variant="destructive" onClick={handleDeleteUser}>
              <Trash size={14} /> Delete
            </Button>
          </div>
        </CardContent>
      </Card>

      {/* Orders */}
      <h2 className="text-xl font-semibold">Orders</h2>

      {orders.length === 0 ? (
        <p>No orders</p>
      ) : (
        <div className="grid md:grid-cols-3 gap-4">
          {orders.map((order) => {
            const status = order.status?.toLowerCase();

            return (
              <Card key={order._id}>
                <CardHeader>
                  <CardTitle>                    <p className="font-semibold">Products:</p>

                    {order.items && order.items.length > 0 ? (
                      order.items.map((item: any, index: number) => (
                        <p key={index} className="text-sm text-gray-600">
                          {item.name || "No Name"} (x{item.quantity || 1})
                        </p>
                      ))
                    ) : (
                      <p className="text-sm text-gray-400">No items</p>
                    )}</CardTitle>
                </CardHeader>

                <CardContent>
                  <p>
                    Date:{" "}
                    {order.createdAt
                      ? new Date(order.createdAt).toLocaleDateString()
                      : "N/A"}
                  </p>

               
                  <p>Total: ₹{order.total}</p>

               
                  <p className="font-medium">
                    Status:{" "}
                    <span
                      className={
                        status === "pending"
                          ? "text-yellow-600"
                          : status === "shipped"
                            ? "text-blue-600"
                            : status === "delivered"
                              ? "text-green-600"
                              : "text-red-600"
                      }
                    >
                      {order.status}
                    </span>
                  </p>

                  {status !== "cancelled" && status !== "delivered" && (
                    <Button
                      className="mt-3 bg-red-500 hover:bg-red-600 text-white"
                      onClick={() => handleCancelOrder(order._id)}
                    >
                      Cancel Order
                    </Button>
                  )}
                </CardContent>
              </Card>
            );
          })}
        </div>
      )}

      {/* Edit Dialog */}
      <Dialog open={openEditDialog} onOpenChange={setOpenEditDialog}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Edit User</DialogTitle>
          </DialogHeader>

          <Input
            value={editForm.name}
            onChange={(e) => setEditForm({ ...editForm, name: e.target.value })}
          />

          <Input
            value={editForm.email}
            onChange={(e) => setEditForm({ ...editForm, email: e.target.value })}
          />
          <DialogFooter>
            <Button onClick={() => setOpenEditDialog(false)}>Cancel</Button>
            <Button onClick={handleSaveEdit}>Save</Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}